  public enum DGCTypeEnum: SwiftProtobuf.Enum {
    public typealias RawValue = Int
    case unknown // = 0

    /// 发送福袋
    case send // = 1

    /// 福袋过期
    case expire // = 2

    /// 福袋被领取完
    case receivedAll // = 3
    case UNRECOGNIZED(Int)

    public init() {
      self = .unknown
    }

    public init?(rawValue: Int) {
      switch rawValue {
      case 0: self = .unknown
      case 1: self = .send
      case 2: self = .expire
      case 3: self = .receivedAll
      default: self = .UNRECOGNIZED(rawValue)
      }
    }

    public var rawValue: Int {
      switch self {
      case .unknown: return 0
      case .send: return 1
      case .expire: return 2
      case .receivedAll: return 3
      case .UNRECOGNIZED(let i): return i
      }
    }

  }

  public init() {}
}

